quick_start.install:
# Requires GAMS or AMPL installation
# Via GAMS: gams model.gms solver=baron
# Via AMPL: option solver baron; solve;

quick_start.code:
using JuMP, HiGHS

model = Model(HiGHS.Optimizer)
@variable(model, 0 <= x <= 10)
@objective(model, Max, x)
optimize!(model)
println("Optimal: $(value(x))")

from gams import GamsWorkspace

ws = GamsWorkspace()
job = ws.add_job_from_string("""
Variable x, z;
Positive Variable x;
x.up = 10;
Equation obj;
obj.. z =e= x;
Model m /all/;
Solve m using lp maximizing z;
""")
job.run()
